public async Task<bool> PurchaseTicketAsync(int eventId, int quantity)
{
    using (var context = new EventDbContext())
    {
        using (var transaction = context.Database.BeginTransaction())
        {
            try
            {
                var eventDetail = await context.Events.SingleOrDefaultAsync(e => e.Id == eventId);

                if (eventDetail == null || eventDetail.AvailableSeats < quantity)
                {
                    return false;
                }

                eventDetail.AvailableSeats -= quantity;

                context.Entry(eventDetail).State = EntityState.Modified;

                await context.SaveChangesAsync();

                transaction.Commit();
                return true;
            }
            catch (Exception)
            {
                transaction.Rollback();
                return false;
            }
        }
    }
}